fused_kernel_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <math.h>

__device__ float gelu_approx(float x) {
    return 0.5f * x * (1.0f + tanhf(0.7978845608028654f * (x + 0.044715f * x * x * x)));
}

__global__ void fused_matmul_avgpool_gelu_scale_max_kernel(
    const float* input,
    const float* weight,
    const float* bias,
    float* output,
    int batch_size,
    int in_features,
    int out_features,
    int pool_kernel_size,
    float scale_factor
) {
    // Each thread block processes one batch
    int batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    // Shared memory for pooling results
    extern __shared__ float shared_mem[];

    const float* input_ptr = input + batch_idx * in_features;
    int pooled_features = out_features / pool_kernel_size;

    // Phase 1: Matrix multiplication, pooling, GELU, and scaling
    for (int pool_idx = threadIdx.x; pool_idx < pooled_features; pool_idx += blockDim.x) {
        float pool_sum = 0.0f;

        // Compute matmul for all features in this pool
        for (int k = 0; k < pool_kernel_size; k++) {
            int feat_idx = pool_idx * pool_kernel_size + k;
            float sum = 0.0f;
            const float* weight_ptr = weight + feat_idx * in_features;

            // Dot product
            for (int i = 0; i < in_features; i++) {
                sum += input_ptr[i] * weight_ptr[i];
            }

            // Add bias
            if (bias != nullptr) {
                sum += bias[feat_idx];
            }

            pool_sum += sum;
        }

        // Average pooling
        float avg_val = pool_sum / pool_kernel_size;

        // Apply GELU
        avg_val = gelu_approx(avg_val);

        // Apply scaling
        avg_val *= scale_factor;

        shared_mem[pool_idx] = avg_val;
    }
    __syncthreads();

    // Phase 2: Max reduction across pooled features
    // Use parallel reduction within the block
    int tid = threadIdx.x;
    int stride = blockDim.x;

    // Each thread handles multiple elements if needed
    for (int s = stride; s > 0; s >>= 1) {
        if (tid < s && tid + s < pooled_features) {
            shared_mem[tid] = fmaxf(shared_mem[tid], shared_mem[tid + s]);
        }
        __syncthreads();
    }

    // Thread 0 writes the final result
    if (tid == 0) {
        output[batch_idx] = shared_mem[0];
    }
